// ✅ UPDATED: src/pages/OfficialControlScreen.js
// Fully wired to API using `ref` passed from HomeScreen

import React, { useEffect, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Pressable,
  ScrollView,
  ActivityIndicator,
} from "react-native";
import { useNavigation, useRoute } from "@react-navigation/native";
import { useTranslation } from "../i18n";

export default function OfficialControlScreen() {
  const navigation = useNavigation();
  const route = useRoute();
  const { t } = useTranslation();

  // =============================
  // 1️⃣ READ REF
  // =============================
  const ref = route?.params?.ref;

  // =============================
  // 2️⃣ STATE
  // =============================
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const [data, setData] = useState(null);

  // =============================
  // 3️⃣ FETCH OFFICIAL DATA
  // =============================
  useEffect(() => {
    if (!ref) {
      setLoading(false);
      setError(true);
      return;
    }

    setLoading(true);
    setError(false);

    fetch(
      `https://api.taxidevilleyaounde.com/api/vehicles/${ref}/qr`
    )
      .then((res) => res.json())
      .then((json) => {
        if (!json?.success) {
          throw new Error("Not found");
        }
        setData(json);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setError(true);
        setLoading(false);
      });
  }, [ref]);

  // =============================
  // 4️⃣ LOADING / ERROR
  // =============================
  if (loading) {
    return (
      <SafeAreaView style={styles.safe}>
        <View style={{ flex: 1, justifyContent: "center", alignItems: "center" }}>
          <ActivityIndicator size="large" color="#2F7D3A" />
        </View>
      </SafeAreaView>
    );
  }

  if (error || !data) {
    return (
      <SafeAreaView style={styles.safe}>
        <View style={{ flex: 1, justifyContent: "center", alignItems: "center" }}>
          <Text style={{ color: "red", fontSize: 16 }}>
            {t("errors.vehicleNotFound")}
          </Text>
        </View>
      </SafeAreaView>
    );
  }

  // =============================
  // 5️⃣ MAP API → UI DATA
  // =============================
  const vehicle = data.identificationVehicule || {};
  const licence = data.autorisationExercer || {};
  const driver = data.profilChauffeur || {};
  const insurance = data.assurance || {};

  // =============================
  // 6️⃣ RENDER
  // =============================
  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
      >
        {/* ===== Back ===== */}
        <View style={styles.topRow}>
          <Pressable style={styles.backBtn} onPress={() => navigation.goBack()}>
            <Text style={styles.backIcon}>‹</Text>
            <Text style={styles.backText}>{t("common.back")}</Text>
          </Pressable>
        </View>

        {/* ===== Status Banner ===== */}
        <View style={styles.bannerWrap}>
          <View style={styles.banner}>
            <View style={styles.bannerDot} />
            <Text style={styles.bannerText}>
              {t("official.statusAuthorized")}
            </Text>
          </View>
        </View>

        {/* ===== VEHICLE ===== */}
        <SectionCard
          icon="🚕"
          title={t("official.vehicle.title")}
          subtitle={`(${t("official.vehicle.subtitle")})`}
          rows={[
            {
              icon: "🚗",
              label: t("official.vehicle.plate"),
              value: vehicle.immatriculation,
            },
            {
              icon: "🚕",
              label: t("official.vehicle.model"),
              value: vehicle.marqueModele,
            },
            {
              icon: "📍",
              label: t("official.vehicle.owner"),
              value: vehicle.proprietaire,
            },
          ]}
        />

        {/* ===== LICENCE ===== */}
        <SectionCard
          icon="✅"
          title={t("official.licence.title")}
          subtitle={`(${t("official.licence.subtitle")})`}
          rows={[
            {
              icon: "🆔",
              label: t("official.licence.number"),
              value: licence.numeroLicence ?? "—",
            },
            {
              icon: "🕒",
              label: t("official.licence.validity"),
              value:
                licence.validiteDebut && licence.validiteFin
                  ? `${licence.validiteDebut} → ${licence.validiteFin}`
                  : "—",
            },
            {
              icon: "📍",
              label: t("official.licence.zone"),
              value: licence.zone ?? "—",
            },
            {
              icon: "🚕",
              label: t("official.licence.doorNumber"),
              value: licence.numeroPortiere ?? "—",
            },
          ]}
          headerVariant="green"
        />

        {/* ===== DRIVER ===== */}
        <SectionCard
          icon="🧑🏾‍✈️"
          title={t("official.driver.title")}
          subtitle={`(${t("official.driver.subtitle")})`}
          rows={[
            {
              icon: "🪪",
              label: t("official.driver.permit"),
              value: driver.numeroPermis ?? "—",
            },
            {
              icon: "🅱️",
              label: t("official.driver.category"),
              value: driver.categorie ?? "—",
            },
            {
              icon: "🆔",
              label: t("official.driver.cni"),
              value: driver.numeroCNI ?? "—",
            },
          ]}
          headerVariant="green"
          topLeftAvatar={{
            initials: driver.noms
              ? driver.noms
                  .split(" ")
                  .map((n) => n[0])
                  .slice(0, 2)
                  .join("")
              : "—",
            name: driver.noms ?? "—",
          }}
        />

        {/* ===== INSURANCE ===== */}
        <SectionCard
          icon="🛡️"
          title={t("official.insurance.title")}
          subtitle={`(${t("official.insurance.subtitle")})`}
          rows={[
            {
              icon: "🏢",
              label: t("official.insurance.company"),
              value: insurance.compagnie ?? "—",
            },
            {
              icon: "🕒",
              label: t("official.insurance.expiry"),
              value: insurance.expiration ?? "—",
            },
            {
              icon: "✅",
              label: t("official.insurance.status"),
              value: insurance.statut ?? "—",
              isStatus: true,
            },
          ]}
          headerVariant="green"
        />
      </ScrollView>
    </SafeAreaView>
  );
}

/* =========================
   SECTION CARD (UNCHANGED)
========================= */
function SectionCard({ icon, title, subtitle, rows, headerVariant = "green", topLeftAvatar }) {
  return (
    <View style={styles.card}>
      <View style={[styles.sectionHeader, headerVariant === "green" && styles.sectionHeaderGreen]}>
        <Text style={styles.sectionHeaderIcon}>{icon}</Text>
        <View style={{ flex: 1 }}>
          <Text style={styles.sectionHeaderTitle}>
            {title} <Text style={styles.sectionHeaderSub}>{subtitle}</Text>
          </Text>
        </View>
      </View>

      {topLeftAvatar ? (
        <View style={styles.avatarRow}>
          <View style={styles.avatarCircle}>
            <Text style={styles.avatarText}>{topLeftAvatar.initials}</Text>
          </View>
          <Text style={styles.avatarName}>{topLeftAvatar.name}</Text>
        </View>
      ) : null}

      {rows.map((r, idx) => (
        <View key={idx} style={[styles.row, idx === rows.length - 1 && styles.rowLast]}>
          <Text style={styles.rowIcon}>{r.icon}</Text>
          <Text style={styles.rowLabel} numberOfLines={1}>
            {r.label} :
          </Text>
          {r.isStatus ? (
            <View style={styles.statusChip}>
              <Text style={styles.statusChipText}>{r.value}</Text>
            </View>
          ) : (
            <Text style={styles.rowValue}>{r.value}</Text>
          )}
        </View>
      ))}
    </View>
  );
}

/* =========================
   STYLES (UNCHANGED)
========================= */

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";
const HEADER_GREEN = "#DCEEDD";
const TEXT_DARK = "#0B1F14";
const MUTED_GREEN = "#4B6B57";
const CARD_BG = "#FFFFFF";
const PAGE_BG = "#EEF5F4";

/* styles object stays exactly as you already had it */
